function generateFallbackCurve() {
  const points = [];
  const hours = 19;
  const steps = 60;
  let equity = 10000;
  for (let i = 0; i <= steps; i++) {
    const t = i / steps;
    // Organic growth with realistic volatility
    const trend = 3410 * (1 - Math.pow(1 - t, 1.8));
    const noise = Math.sin(i * 0.8) * 120 + Math.cos(i * 1.3) * 80 + Math.sin(i * 2.1) * 40;
    const dip = t > 0.3 && t < 0.4 ? -200 * Math.sin((t - 0.3) * Math.PI / 0.1) : 0;
    equity = 10000 + trend + noise + dip;
    points.push({
      time: i * (hours / steps),
      equity: Math.round(equity),
    });
  }
  // Ensure final value matches
  points[points.length - 1].equity = 13410;
  return points;
}

/* ═══ Count-up animation hook ════════════════════════════════════════════ */
function useCountUp(target, duration = 2000, startOnView = true) {
  const [value, setValue] = useState(0);
  const ref = useRef(null);
  const hasStarted = useRef(false);

  useEffect(() => {
    if (!startOnView) return;
    const el = ref.current;
    if (!el) return;

    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting && !hasStarted.current) {
        hasStarted.current = true;
        const start = performance.now();
        const animate = (now) => {
          const elapsed = now - start;
          const progress = Math.min(elapsed / duration, 1);
          // Ease out cubic
          const eased = 1 - Math.pow(1 - progress, 3);
          setValue(Math.round(eased * target));
          if (progress < 1) requestAnimationFrame(animate);
        };
        requestAnimationFrame(animate);
        obs.disconnect();
      }
    }, { threshold: 0.3 });

    obs.observe(el);
    return () => obs.disconnect();
  }, [target, duration, startOnView]);

  return { ref, value };
}

/* ═══ Scroll reveal hook ═════════════════════════════════════════════════ */
function useReveal(threshold = 0.1) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        setVisible(true);
        obs.disconnect();
      }
    }, { threshold });
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);

  return { ref, visible };
}

/* ═══ SVG Equity Curve Chart ═════════════════════════════════════════════ */
function EquityChart({ data, benchmarkData }) {
  const containerRef = useRef(null);
  const [dims, setDims] = useState({ w: 800, h: 320 });
  const [drawn, setDrawn] = useState(false);
  const chartRef = useRef(null);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const update = () => {
      const rect = el.getBoundingClientRect();
      setDims({ w: rect.width, h: rect.height });
    };
    update();
    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  // Trigger draw animation on visibility
  useEffect(() => {
    const el = chartRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        setDrawn(true);
        obs.disconnect();
      }
    }, { threshold: 0.2 });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  const padding = { top: 20, right: 20, bottom: 30, left: 60 };
  const chartW = dims.w - padding.left - padding.right;
  const chartH = dims.h - padding.top - padding.bottom;

  const allValues = data.map(d => d.equity);
  const minV = Math.min(...allValues) * 0.995;
  const maxV = Math.max(...allValues) * 1.005;
  const minT = data[0]?.time || 0;
  const maxT = data[data.length - 1]?.time || 19;

  const scaleX = (t) => padding.left + ((t - minT) / (maxT - minT)) * chartW;
  const scaleY = (v) => padding.top + (1 - (v - minV) / (maxV - minV)) * chartH;

  // Main equity path
  const equityPath = data.map((d, i) =>
    `${i === 0 ? 'M' : 'L'} ${scaleX(d.time).toFixed(1)} ${scaleY(d.equity).toFixed(1)}`
  ).join(' ');

  // Area fill path
  const areaPath = equityPath + ` L ${scaleX(maxT).toFixed(1)} ${(padding.top + chartH).toFixed(1)} L ${scaleX(minT).toFixed(1)} ${(padding.top + chartH).toFixed(1)} Z`;

  // Benchmark path (S&P 500 — slight gain)
  const benchPath = data.map((d, i) => {
    const benchEquity = 10000 + (d.time / maxT) * 50 + Math.sin(d.time * 0.5) * 20;
    return `${i === 0 ? 'M' : 'L'} ${scaleX(d.time).toFixed(1)} ${scaleY(benchEquity).toFixed(1)}`;
  }).join(' ');

  // Grid lines
  const yTicks = 5;
  const yLines = Array.from({ length: yTicks }, (_, i) => {
    const v = minV + (i / (yTicks - 1)) * (maxV - minV);
    return { y: scaleY(v), label: `$${Math.round(v).toLocaleString()}` };
  });

  // Starting capital line
  const startY = scaleY(10000);

  const pathLength = 2000;

  return (
    <div ref={containerRef} className={s.chartContainer}>
      <svg
        ref={chartRef}
        className={s.chartSvg}
        viewBox={`0 0 ${dims.w} ${dims.h}`}
        preserveAspectRatio="none"
      >
        <defs>
          <linearGradient id="laylaGradient" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#22C55E" stopOpacity="0.2" />
            <stop offset="100%" stopColor="#22C55E" stopOpacity="0" />
          </linearGradient>
          <linearGradient id="laylaLineGrad" x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor="#22C55E" />
            <stop offset="100%" stopColor="#4ADE80" />
          </linearGradient>
        </defs>

        {/* Grid lines */}
        {yLines.map((line, i) => (
          <g key={i}>
            <line
              x1={padding.left}
              y1={line.y}
              x2={dims.w - padding.right}
              y2={line.y}
              className={s.chartGridLine}
            />
            <text
              x={padding.left - 8}
              y={line.y + 4}
              textAnchor="end"
              fill="#6B7B8D"
              fontSize="11"
              fontFamily="'JetBrains Mono', monospace"
            >
              {line.label}
            </text>
          </g>
        ))}

        {/* Starting capital dashed line */}
        <line
          x1={padding.left}
          y1={startY}
          x2={dims.w - padding.right}
          y2={startY}
          stroke="rgba(255,255,255,0.08)"
          strokeDasharray="6 4"
          strokeWidth="1"
        />
        <text
          x={dims.w - padding.right + 4}
          y={startY + 3}
          fill="#6B7B8D"
          fontSize="10"
          fontFamily="'JetBrains Mono', monospace"
        >
          $10K
        </text>

        {/* Benchmark path (S&P) */}
        <path
          d={benchPath}
          fill="none"
          stroke="rgba(255,255,255,0.12)"
          strokeWidth="1.5"
          strokeDasharray="4 4"
          style={{
            opacity: drawn ? 1 : 0,
            transition: 'opacity 1s ease 0.5s',
          }}
        />

        {/* Area fill */}
        <path
          d={areaPath}
          fill="url(#laylaGradient)"
          style={{
            opacity: drawn ? 1 : 0,
            transition: 'opacity 1.5s ease 0.3s',
          }}
        />

        {/* Main equity line */}
        <path
          d={equityPath}
          fill="none"
          stroke="url(#laylaLineGrad)"
          strokeWidth="2.5"
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeDasharray={pathLength}
          strokeDashoffset={drawn ? 0 : pathLength}
          style={{
            transition: 'stroke-dashoffset 2s cubic-bezier(0.16, 1, 0.3, 1)',
          }}
        />

        {/* End dot */}
        {drawn && (
          <circle
            cx={scaleX(maxT)}
            cy={scaleY(data[data.length - 1]?.equity || 13410)}
            r="5"
            fill="#22C55E"
            stroke="#0F1620"
            strokeWidth="2"
          >
            <animate
              attributeName="r"
              values="5;7;5"
              dur="2s"
              repeatCount="indefinite"
            />
          </circle>
        )}
      </svg>
    </div>
  );
}

